from dataclasses import dataclass
from enum import Enum

class PolicyAction(Enum):
    ALLOW   = "allow"
    DENY    = "deny"
    REDACT  = "redact_and_allow"

@dataclass
class ModelEndpoint:
    name: str
    tier: str            # any / dpa_covered / private_endpoint / self_hosted
    supports_label: SensitivityLevel  # maximum label this endpoint handles

ENDPOINTS: dict[str, ModelEndpoint] = {
    "gpt-4o-public":    ModelEndpoint("gpt-4o-public",    "any",              SensitivityLevel.INTERNAL),
    "gpt-4o-dpa":       ModelEndpoint("gpt-4o-dpa",       "dpa_covered",      SensitivityLevel.CONFIDENTIAL),
    "claude-private":   ModelEndpoint("claude-private",   "private_endpoint", SensitivityLevel.RESTRICTED),
    "llama-selfhosted": ModelEndpoint("llama-selfhosted", "self_hosted",      SensitivityLevel.REGULATED),
}

@dataclass
class PolicyDecision:
    action: PolicyAction
    endpoint: ModelEndpoint | None
    storage_tier: str
    reason: str

def evaluate_policy(prompt: LabeledPrompt,
                    requested_endpoint: str) -> PolicyDecision:
    endpoint = ENDPOINTS.get(requested_endpoint)
    if endpoint is None:
        return PolicyDecision(PolicyAction.DENY, None, "", "Unknown endpoint")

    # Deny if endpoint cannot handle the sensitivity level
    if prompt.label > endpoint.supports_label:
        return PolicyDecision(
            PolicyAction.DENY, None, "",
            f"{prompt.label.label()} exceeds {endpoint.name} max ({endpoint.supports_label.label()})"
        )

    # Deny credential leakage regardless of label
    if "CREDENTIALS" in prompt.categories:
        return PolicyDecision(
            PolicyAction.DENY, None, "",
            "CREDENTIALS category always denied — redact secrets before submitting"
        )

    # Storage tier assignment
    storage = {
        SensitivityLevel.PUBLIC:       "public_cache",
        SensitivityLevel.INTERNAL:     "public_cache",
        SensitivityLevel.CONFIDENTIAL: "encrypted_store",
        SensitivityLevel.RESTRICTED:   "encrypted_store",
        SensitivityLevel.REGULATED:    "regulated_vault",
    }[prompt.label]

    return PolicyDecision(PolicyAction.ALLOW, endpoint, storage, "Policy satisfied")


# Usage
p = LabeledPrompt.from_text("Draft a severance letter for Sarah Chen (DOB 1985-03-12)", "u-7712")
decision = evaluate_policy(p, "gpt-4o-public")
print(f"Action: {decision.action.value}  Reason: {decision.reason}")
# Action: deny  Reason: CONFIDENTIAL exceeds gpt-4o-public max (INTERNAL)

decision2 = evaluate_policy(p, "gpt-4o-dpa")
print(f"Action: {decision2.action.value}  Storage: {decision2.storage_tier}")
# Action: allow  Storage: encrypted_store

import json, hashlib
from dataclasses import asdict
from pathlib import Path
from datetime import datetime

class LabelAuditLog:
    """Append-only NDJSON log of label events."""

    def __init__(self, path: Path):
        self.path = path
        self.path.parent.mkdir(parents=True, exist_ok=True)

    def _append(self, event: dict) -> None:
        event["logged_at"] = datetime.utcnow().isoformat()
        line = json.dumps(event, default=str)
        with self.path.open("a") as f:
            f.write(line + "\n")

    def log_prompt(self, prompt: LabeledPrompt) -> None:
        self._append({
            "event": "prompt_classified",
            **prompt.to_audit_record(),
        })

    def log_policy_decision(self, prompt: LabeledPrompt,
                            decision: PolicyDecision) -> None:
        self._append({
            "event": "policy_evaluated",
            "trace_id": prompt.trace_id,
            "user_id": prompt.user_id,
            "label": prompt.label.label(),
            "action": decision.action.value,
            "endpoint": decision.endpoint.name if decision.endpoint else None,
            "storage_tier": decision.storage_tier,
            "reason": decision.reason,
        })

    def log_output(self, output: LabeledOutput) -> None:
        self._append({
            "event": "output_classified",
            "trace_id": output.trace_id,
            "user_id": output.user_id,
            "input_label": output.input_label.label(),
            "detected_label": output.detected_label.label(),
            "final_label": output.final_label.label(),
            "promoted": output.was_promoted(),
            "categories": sorted(output.categories),
            "storage_tier": output.storage_tier,
        })

    def entries_for_trace(self, trace_id: str) -> list[dict]:
        if not self.path.exists():
            return []
        return [
            json.loads(line)
            for line in self.path.read_text().splitlines()
            if json.loads(line).get("trace_id") == trace_id
        ]
